/*
 * Clarification: Check Points (and commits)
 * Being able to set autoCommit=false allows IndexWriter to flush and
 * write new index files to the directory without writing a new segments_N
 * file which references these new files. It also means that the state of
 * the in memory SegmentInfos object is different than the most recent
 * segments_N file written to the directory.
 *
 * Each time the SegmentInfos is changed, and matches the (possibly
 * modified) directory files, we have a new "check point".
 * If the modified/new SegmentInfos is written to disk - as a new
 * (generation of) segments_N file - this check point is also an
 * IndexCommit.
 *
 * With autoCommit=true, every checkPoint is also a CommitPoint.
 * With autoCommit=false, some checkPoints may not be commits.
 *
 * A new checkpoint always replaces the previous checkpoint and
 * becomes the new "front" of the index. This allows the IndexFileDeleter
 * to delete files that are referenced only by stale checkpoints.
 * (files that were created since the last commit, but are no longer
 * referenced by the "front" of the index). For this, IndexFileDeleter
 * keeps track of the last non commit checkpoint.
 */
public class IndexWriter {
public IndexWriter(Directory d, Analyzer a, boolean create)
       throws CorruptIndexException, LockObtainFailedException, IOException {
    init(d, a, create, null, true, DEFAULT_MAX_FIELD_LENGTH, null, null);
  }

public IndexWriter(Directory d, Analyzer a)
    throws CorruptIndexException, LockObtainFailedException, IOException {
    init(d, a, null, true, DEFAULT_MAX_FIELD_LENGTH, null, null);
  }

public IndexWriter(Directory d, boolean autoCommit, Analyzer a)
    throws CorruptIndexException, LockObtainFailedException, IOException {
    init(d, a, null, autoCommit, DEFAULT_MAX_FIELD_LENGTH, null, null);
  }

public IndexWriter(Directory d, boolean autoCommit, Analyzer a, boolean create)
       throws CorruptIndexException, LockObtainFailedException, IOException {
    init(d, a, create, null, autoCommit, DEFAULT_MAX_FIELD_LENGTH, null, null);
  }

public IndexWriter(Directory d, boolean autoCommit, Analyzer a, IndexDeletionPolicy deletionPolicy)
    throws CorruptIndexException, LockObtainFailedException, IOException {
    init(d, a, deletionPolicy, autoCommit, DEFAULT_MAX_FIELD_LENGTH, null, null);
  }

public IndexWriter(Directory d, boolean autoCommit, Analyzer a, boolean create, IndexDeletionPolicy deletionPolicy)
          throws CorruptIndexException, LockObtainFailedException, IOException {
    init(d, a, create, deletionPolicy, autoCommit, DEFAULT_MAX_FIELD_LENGTH, null, null);
  }

private void init(Directory d, Analyzer a, final boolean create,
                    IndexDeletionPolicy deletionPolicy, boolean autoCommit, int maxFieldLength,
                    IndexingChain indexingChain, IndexCommit commit)
    throws CorruptIndexException, LockObtainFailedException, IOException {
    directory = d;
    analyzer = a;
    setMessageID(defaultInfoStream);
    this.maxFieldLength = maxFieldLength;
    if (indexingChain == null)
      indexingChain = DocumentsWriter.DefaultIndexingChain;
    if (create) {
      directory.clearLock(WRITE_LOCK_NAME);
    }
    Lock writeLock = directory.makeLock(WRITE_LOCK_NAME);
    if (!writeLock.obtain(writeLockTimeout))
      throw new LockObtainFailedException("Index locked for write: " + writeLock);
    this.writeLock = writeLock;
    try {
      if (create) {
        boolean doCommit;
        try {
          segmentInfos.read(directory);
          segmentInfos.clear();
          doCommit = false;
        } catch (IOException e) {
          doCommit = true;
        }
        if (autoCommit || doCommit) {
          segmentInfos.commit(directory);
          synced.addAll(segmentInfos.files(directory, true));
        } else {
          changeCount++;
        }
      } else {
        segmentInfos.read(directory);
        if (commit != null) {
          if (commit.getDirectory() != directory)
            throw new IllegalArgumentException("IndexCommit's directory doesn't match my directory");
          SegmentInfos oldInfos = new SegmentInfos();
          oldInfos.read(directory, commit.getSegmentsFileName());
          segmentInfos.replace(oldInfos);
          changeCount++;
          if (infoStream != null)
            message("init: loaded commit \"" + commit.getSegmentsFileName() + "\"");
        }
        synced.addAll(segmentInfos.files(directory, true));
      }
      this.autoCommit = autoCommit;
      setRollbackSegmentInfos(segmentInfos);
      docWriter = new DocumentsWriter(directory, this, indexingChain);
      docWriter.setInfoStream(infoStream);
      docWriter.setMaxFieldLength(maxFieldLength);
      deleter = new IndexFileDeleter(directory,
                                     deletionPolicy == null ? new KeepOnlyLastCommitDeletionPolicy() : deletionPolicy,
                                     segmentInfos, infoStream, docWriter);
      if (deleter.startingCommitDeleted)
        changeCount++;
      pushMaxBufferedDocs();
      if (infoStream != null) {
        message("init: create=" + create);
        messageState();
      }
    } catch (IOException e) {
      this.writeLock.release();
      this.writeLock = null;
      throw e;
    }
  }

public double getMaxSyncPauseSeconds() {
    return maxSyncPauseSeconds;
  }

public void setMaxSyncPauseSeconds(double seconds) {
    maxSyncPauseSeconds = seconds;
  }

private void messageState() {
    message("setInfoStream: dir=" + directory +
            " autoCommit=" + autoCommit +
            " mergePolicy=" + mergePolicy +
            " mergeScheduler=" + mergeScheduler +
            " ramBufferSizeMB=" + docWriter.getRAMBufferSizeMB() +
            " maxBufferedDocs=" + docWriter.getMaxBufferedDocs() +
            " maxBuffereDeleteTerms=" + docWriter.getMaxBufferedDeleteTerms() +
            " maxFieldLength=" + maxFieldLength +
            " index=" + segString());
  }

private synchronized boolean flushDocStores() throws IOException {
    boolean useCompoundDocStore = false;
    String docStoreSegment;
    boolean success = false;
    try {
      docStoreSegment = docWriter.closeDocStore();
      success = true;
    } finally {
      if (!success && infoStream != null) {
        message("hit exception closing doc store segment");
      }
    }
    useCompoundDocStore = mergePolicy.useCompoundDocStore(segmentInfos);
    if (useCompoundDocStore && docStoreSegment != null && docWriter.closedFiles().size() != 0) {
      if (infoStream != null) {
        message("create compound file " + docStoreSegment + "." + IndexFileNames.COMPOUND_FILE_STORE_EXTENSION);
      }
      success = false;
      final int numSegments = segmentInfos.size();
      final String compoundFileName = docStoreSegment + "." + IndexFileNames.COMPOUND_FILE_STORE_EXTENSION;
      try {
        CompoundFileWriter cfsWriter = new CompoundFileWriter(directory, compoundFileName);
        final Iterator it = docWriter.closedFiles().iterator();
        while(it.hasNext())
          cfsWriter.addFile((String) it.next());
        cfsWriter.close();
        success = true;
      } finally {
        if (!success) {
          if (infoStream != null)
            message("hit exception building compound file doc store for segment " + docStoreSegment);
          deleter.deleteFile(compoundFileName);
        }
      }
      for(int i=0;i<numSegments;i++) {
        SegmentInfo si = segmentInfos.info(i);
        if (si.getDocStoreOffset() != -1 &&
            si.getDocStoreSegment().equals(docStoreSegment))
          si.setDocStoreIsCompoundFile(true);
      }
      checkpoint();
      deleter.deleteNewFiles(docWriter.closedFiles());
    }
    return useCompoundDocStore;
  }

private synchronized final boolean doFlushInternal(boolean flushDocStores, boolean flushDeletes) throws CorruptIndexException, IOException {
    if (hitOOM) {
      throw new IllegalStateException("this writer hit an OutOfMemoryError; cannot flush");
    }
    ensureOpen(false);
    assert testPoint("startDoFlush");
    flushCount++;
    flushDeletes |= docWriter.doApplyDeletes();
    flushDeletes |= autoCommit;
    if (docWriter.pauseAllThreads()) {
      docWriter.resumeAllThreads();
      return false;
    }
    try {
      SegmentInfo newSegment = null;
      final int numDocs = docWriter.getNumDocsInRAM();
      boolean flushDocs = numDocs > 0;
      flushDocStores |= autoCommit;
      String docStoreSegment = docWriter.getDocStoreSegment();
      assert docStoreSegment != null || numDocs == 0;
      if (docStoreSegment == null)
        flushDocStores = false;
      int docStoreOffset = docWriter.getDocStoreOffset();
      assert !autoCommit || 0 == docStoreOffset;
      boolean docStoreIsCompoundFile = false;
      if (infoStream != null) {
        message("  flush: segment=" + docWriter.getSegment() +
                " docStoreSegment=" + docWriter.getDocStoreSegment() +
                " docStoreOffset=" + docStoreOffset +
                " flushDocs=" + flushDocs +
                " flushDeletes=" + flushDeletes +
                " flushDocStores=" + flushDocStores +
                " numDocs=" + numDocs +
                " numBufDelTerms=" + docWriter.getNumBufferedDeleteTerms());
        message("  index before flush " + segString());
      }
      if (flushDocStores && (!flushDocs || !docWriter.getSegment().equals(docWriter.getDocStoreSegment()))) {
        if (infoStream != null)
          message("  flush shared docStore segment " + docStoreSegment);
        docStoreIsCompoundFile = flushDocStores();
        flushDocStores = false;
      }
      String segment = docWriter.getSegment();
      assert segment != null || !flushDocs;
      if (flushDocs) {
        boolean success = false;
        final int flushedDocCount;
        try {
          flushedDocCount = docWriter.flush(flushDocStores);
          success = true;
        } finally {
          if (!success) {
            if (infoStream != null)
              message("hit exception flushing segment " + segment);
            deleter.refresh(segment);
          }
        }
        if (0 == docStoreOffset && flushDocStores) {
          assert docStoreSegment != null;
          assert docStoreSegment.equals(segment);
          docStoreOffset = -1;
          docStoreIsCompoundFile = false;
          docStoreSegment = null;
        }
        newSegment = new SegmentInfo(segment,
                                     flushedDocCount,
                                     directory, false, true,
                                     docStoreOffset, docStoreSegment,
                                     docStoreIsCompoundFile,
                                     docWriter.hasProx());
        setDiagnostics(newSegment, "flush");
      }
      docWriter.pushDeletes();
      if (flushDocs) {
        segmentInfos.add(newSegment);
        checkpoint();
      }
      if (flushDocs && mergePolicy.useCompoundFile(segmentInfos, newSegment)) {
        boolean success = false;
        try {
          docWriter.createCompoundFile(segment);
          success = true;
        } finally {
          if (!success) {
            if (infoStream != null)
              message("hit exception creating compound file for newly flushed segment " + segment);
            deleter.deleteFile(segment + "." + IndexFileNames.COMPOUND_FILE_EXTENSION);
          }
        }
        newSegment.setUseCompoundFile(true);
        checkpoint();
      }
      if (flushDeletes) {
        flushDeletesCount++;
        applyDeletes();
      }
      if (flushDocs)
        checkpoint();
      doAfterFlush();
      return flushDocs;
    } catch (OutOfMemoryError oom) {
      handleOOM(oom, "doFlush");
      return false;
    } finally {
      docWriter.resumeAllThreads();
    }
  }
}

